indi','India'=>'Indien','Pakistan'=>'Pakistan','Hungarian'=>'Ungarsk','Hungary'=>'Ungarn','Indonesian'=>'Indonesisk','Indonesia'=>'Indonesia','Italian'=>'Italiensk','Italy'=>'Italien','Japanese'=>'Japansk','Japan'=>'Japan','Korean'=>'Koreansk','South Korea'=>'Syd Korea','North Korea'=>'Nordkorea','Polish'=>'Polsk','Poland'=>'Polen','Portuguese'=>'Portugisisk','Portugal'=>'Portugal','Brazil'=>'Brasilien','Mozambique'=>'Mozambique','Angola'=>'Angola','Russian'=>'Russisk','Russia'=>'Rusland','Kazakhstan'=>'Kazakhstan','Belarus'=>'Hviderusland','Kyrgyzstan'=>'Kyrgyzstan','Tajikistan'=>'Tadsjikistan','Spanish'=>'Spansk','Spain'=>'Spanien','Mexico'=>'Mexico','Argentina'=>'Argentina','Colombia'=>'Colombia','Peru'=>'Peru','Ecuador'=>'Ecuador','Bolivia'=>'Bolivia','Chile'=>'Chile','Equatorial Guinea'=>'Equatorial Guinea','Guatemala'=>'Guatemala','Cuba'=>'Cuba','Dominican Republic'=>'Dominican Republic','Honduras'=>'Honduras','Paraguay'=>'Paraguay','El Salvador'=>'El Salvador','Nicaragua'=>'Nicaragua','Costa Rica'=>'Costa Rica','Panama'=>'Panama','Uruguay'=>'Uruguay','Swedish'=>'Svensk','Sweden'=>'Sverige','Turkish'=>'Tyrkisk','Turkey'=>'Tyrkiet','Ukrainian'=>'Ukrainsk','Ukraine'=>'Ukraine','Vietnamese'=>'Vietnamesisk','Vietnam'=>'Vietnam','Bottom right'=>'Nederst til højre','Bottom center'=>'Nederst i midten','Bottom left'=>'Nederst til venstre','None'=>'Ingen','Light - Double - Smooth'=>'Lys - Dobbelt - Glat','Light - Double - Square'=>'Lys - Dobbelt - Firkantet','Light - Simple - Smooth'=>'Let - enkel - glat','Light - Simple - Square'=>'Let - enkel - firkantet','Grey - Double - Smooth'=>'Grå - Dobbelt - Glat','Grey - Double - Square'=>'Grå - Dobbelt - Firkantet','Grey - Simple - Smooth'=>'Grå - enkel - glat','Grey - Simple - Square'=>'Grå - enkel - firkantet','Dark - Double - Smooth'=>'Mørk - Dobbelt - Glat','Dark - Double - Square'=>'Mørk - Dobbelt - Firkantet','Dark - Simple - Smooth'=>'Mørk - enkel - glat','Dark - Simple - Square'=>'Mørk - enkel - firkantet','Blur Black - Double - Smooth'=>'Blur Black - Dobbelt - Glat','Blur Black - Double - Square'=>'Blur Black - Dobbelt - Firkantet','Blur Black - Simple - Smooth'=>'Blur Black - Enkel - Glat','Blur Black - Simple - Square'=>'Blur Black - Enkel - Firkantet','Blur White - Double - Smooth'=>'Blur White - Dobbelt - Glat','Blur White - Double - Square'=>'Blur White - Dobbelt - Firkantet','Blur White - Simple - Smooth'=>'Slør hvid - enkel - glat','Blur White - Simple - Square'=>'Blur White - Simple - Square','Inline list'=>'Inline-liste','Block'=>'Blok','Dropdown'=>'Dropdown','Original name'=>'Oprindeligt navn','Translated name'=>'Oversat navn','Language ID'=>'Sprog-ID','No display'=>'Intet display','Circle'=>'Cirkel','Rectangular'=>'Rektangulær','Wave'=>'Bølge','Display'=>'Vis','List without current language'=>'Liste uden nuværende sprog','List without active class'=>'Liste uden aktiv klasse','List with active class'=>'Liste med aktiv klasse','Sub-list'=>'Underliste','wpLingua'=>'wpLingua','This URL is excluded from translation'=>'Denne URL er udelukket fra oversættelse','Return on page'=>'Tilbage på siden','Visual editor'=>'Visuel editor','All translations on page'=>'Alle oversættelser på siden','Edit the page slug'=>'Rediger sidens slug','Translations'=>'Oversættelser','Edit translations'=>'Rediger oversættelser','You are about to leave the page without saving your changes. They will be lost if you continue. Would you like to leave the page anyway?'=>'Du er ved at forlade siden uden at gemme dine ændringer. De vil gå tabt, hvis du fortsætter. Vil du gerne forlade siden alligevel?','wpLingua - Dictionary rules'=>'wpLingua - Regler for ordbøger','Debug'=>'Fejlfind','Dictionary entries'=>'Ordbogsopslag','Translation rules by dictionary: '=>'Oversættelsesregler efter ordbog: ','The dictionary allows you to define translation rules that apply when generating machine translations. You can specify words or sets of words that should never be translated, or define how they should be translated for each language.'=>'Ordbogen giver dig mulighed for at definere oversættelsesregler, der gælder, når du genererer maskinoversættelser. Du kan angive ord eller sæt af ord, der aldrig skal oversættes, eller definere, hvordan de skal oversættes for hvert sprog.','Add a dictionary entry'=>'Tilføj et ordbogsopslag','Add an entry'=>'Tilføj en post','Edit the entry'=>'Rediger posten','All dictionary entries: '=>'Alle ordbogsopslag: ','Rule N°'=>'Regel nr','Edit'=>'Rediger','Remove'=>'Fjern','Always translate: '=>'Oversæt altid: ',' - By: '=>' - Af: ','Never translate: '=>'Oversæt aldrig: ','Source text: '=>'Kildetekst: ','Never translate'=>'Oversæt aldrig',' - Always translate by: '=>' - Oversæt altid efter: ','Cancel'=>'Annuller','Save new entry'=>'Gem ny post','Save edited entry'=>'Gem redigeret post','wpLingua - Exclusion rules'=>'wpLingua - Regler for udelukkelse','Exclude URL'=>'Ekskluder URL','Exclude URL from translation: '=>'Udeluk URL fra oversættelse: ','You can exclude from translations pages you wish to offer only in the website\'s original language. To do this, list the REGEXs that match the URL to be excluded, one per line. Examples: '=>'Du kan udelukke sider fra oversættelser, som du kun ønsker at tilbyde på hjemmesidens originalsprog. For at gøre dette skal du angive de REGEX\'er, der matcher den URL, der skal udelukkes, én pr. linje. Eksempler: ','Exclude URL "/my-page/"'=>'Udeluk URL\'en "/my-page/"','Exclude URL starting with "/my-page/"'=>'Ekskluder URL, der starter med "/my-page/"','Exclude URL ending with "/my-page/"'=>'Udeluk URL\'er, der slutter med "/my-page/"','Exclude URL containing "/my-page/"'=>'Ekskluder URL, der indeholder "/my-page/"','Exclude elements'=>'Ekskluder elementer','Exclude HTML elements: '=>'Ekskluder HTML-elementer: ','You can leave some elements of your web pages untranslated. To do this, list below the CSS selectors for the elements to be excluded, one per line. Examples: '=>'Du kan lade nogle elementer på dine websider være uoversatte. For at gøre dette skal du nedenfor angive CSS-selektorer for de elementer, der skal udelukkes, en pr. linje. Eksempler på dette: ','Exclude elements by ID attribute'=>'Ekskluder elementer efter ID-attribut','Exclude elements by class attribute'=>'Ekskluder elementer efter klasseattribut','Exclude elements by CSS selector'=>'Udeluk elementer med CSS-vælger','Save'=>'Gem','wpLingua - Links & Medias'=>'wpLingua - Links og medier','Links & medias'=>'Links og medier','Links and medias translations rules: '=>'Regler for links og medieoversættelser: ','Translation rules on links and media allow different images to be displayed or link URLs to be changed according to the current language. These rules apply to elements such as: link target URLs, image source URLs, iframe source URLs, URLs in intercepted JSONs...'=>'Oversættelsesregler for links og medier gør det muligt at vise forskellige billeder eller ændre link-URL\'er alt efter det aktuelle sprog. Disse regler gælder for elementer som: URL\'er til linkmål, URL\'er til billedkilder, URL\'er til iframe-kilder, URL\'er i opfangede JSON\'er...','Add a rule'=>'Tilføj en regel','All links and medias rules: '=>'Alle links og medier er underlagt regler: ','Mode: '=>'Mode: ','Exactly equal'=>'Præcis lige meget','Partially equal'=>'Delvist lige','Regex'=>'Regex','Error'=>'Fejl','Original: '=>'Original: ','Original URL: '=>'Original URL: ','REGEX'=>'REGEX',' - URL: '=>' - URL: ','Message: '=>'Besked: ','An error occurred with API key.'=>'Der opstod en fejl med API-nøglen.','Invalid API key.'=>'Ugyldig API-nøgle.','An error occurred while creating the API key.'=>'Der opstod en fejl under oprettelsen af API-nøglen.','wpLingua - Register API key'=>'wpLingua - Registrer API-nøgle','API key created'=>'API-nøgle oprettet','API key created and sent by email'=>'API-nøgle oprettet og sendt via e-mail','The API key has been correctly created and sent to the following e-mail address: '=>'API-nøglen er blevet oprettet korrekt og sendt til følgende e-mailadresse: ','Go to your mailbox and copy the API key sent to you (don\'t forget to check the spam section of your mailbox). Then paste it in the section below, and click "Set API key" to make your website multilingual.'=>'Gå til din mailboks, og kopier den API-nøgle, du har fået tilsendt (glem ikke at tjekke spam-afsnittet i din mailboks). Indsæt den derefter i afsnittet nedenfor, og klik på "Indstil API-nøgle" for at gøre din hjemmeside flersproget.','Set API Key'=>'Indstil API-nøgle','Get API key'=>'Hent API-nøgle','Start with wpLingua'=>'Start med wpLingua','You are just a few clicks away from making your website multilingual!'=>'Du er kun få klik fra at gøre din hjemmeside flersproget!','For wpLingua to work, an API key is required so that your website has access to the automatic translation service. On this page you can enter your API key if you already have one, or create one for free.'=>'For at wpLingua kan fungere, kræves der en API-nøgle, så din hjemmeside har adgang til den automatiske oversættelsestjeneste. På denne side kan du indtaste din API-nøgle, hvis du allerede har en, eller oprette en gratis.','An <strong>instantly multilingual website</strong> thanks to automatic text detection and translation. Easy to use, no knowledge required.'=>'En <strong>flersproget hjemmeside</strong> med det samme takket være automatisk tekstregistrering og oversættelse. Let at bruge, kræver ingen viden.','<strong>SEO friendly</strong> to allow search engines to index translated pages. Open up your website and your business to the whole world.'=>'<strong>SEO-venlig</strong>, så søgemaskiner kan indeksere oversatte sider. Åbn din hjemmeside og din virksomhed for hele verden.','All <strong>translations are editable</strong>. Discover the visual editor and edit translations simply by clicking on them. With a fully customizable language switcher.'=>'Alle <strong>oversættelser kan redigeres</strong>. Oplev den visuelle editor og rediger oversættelser ved blot at klikke på dem. Med en fuldt tilpasselig sprogomskifter.','One <strong>free and unlimited</strong> language for personal blogs and non-commercial websites. And many more features!'=>'Et <strong>gratis og ubegrænset</strong> sprog til personlige blogs og ikke-kommercielle hjemmesider. Og mange flere funktioner!','Set API key'=>'Indstil API-nøgle','Advanced API features'=>'Avancerede API-funktioner','Important Notice'=>'Vigtig meddelelse','Website incompatible with string translation'=>'Webstedet er ikke kompatibelt med strengoversættelse','Your website contains a large amount of content, which exceeds the limits of the string translation method used by wpLingua.'=>'Din hjemmeside indeholder en stor mængde indhold, som overskrider grænserne for den strengoversættelsesmetode, der bruges af wpLingua.','Why the website is incompatible'=>'Hvorfor hjemmesiden er uforenelig','wpLingua works by identifying and translating each string of characters individually. On a large website, this method generates a very large number of database entries, causing overload and slowdowns.'=>'wpLingua fungerer ved at identificere og oversætte hver enkelt tegnstreng individuelt. På en stor hjemmeside genererer denne metode et meget stort antal databaseindtastninger, hvilket forårsager overbelastning og forsinkelser.','Recommended solution'=>'Anbefalet løsning','To make large websites multilingual, we recommend using a translation plugin based on content duplication, such as Polylang or WPML. These solutions are specifically designed to efficiently manage large websites.'=>'For at gøre store websteder flersprogede anbefaler vi at bruge et oversættelsesplugin baseret på indholdsdublering, såsom Polylang eller WPML. Disse løsninger er specielt designet til effektivt at administrere store websteder.','Set the wpLingua API key: '=>'Indstil wpLingua API-nøglen: ','If you already have an API key, enter it below. If you\'ve forgotten your website\'s API key, visit'=>'Hvis du allerede har en API-nøgle, skal du indtaste den nedenfor. Hvis du har glemt din hjemmesides API-nøgle, kan du besøge','the API key retrieval page'=>'siden til hentning af API-nøgler','Click to expand'=>'Klik for at læse mere','A wpLingua API key consists of 42 characters (uppercase, lowercase and numbers). It is emailed to you when you request it using the form provided when you install the plugin. You must keep this key secret and only communicate it to wplingua.com services.'=>'En wpLingua API-nøgle består af 42 tegn (store og små bogstaver samt tal). Den sendes til dig, når du anmoder om den ved hjælp af formularen, der følger med, når du installerer pluginet. Du skal holde denne nøgle hemmelig og kun kommunikere den til wplingua.com-tjenester.','Register wpLingua API key: '=>'Registrer wpLingua API-nøgle: ','Claim a wpLingua API key and make your website multilingual in a minute! For a personal blog or a non-commercial website, get one unlimited free language.'=>'Gør krav på en wpLingua API-nøgle, og gør din hjemmeside flersproget på et minut! Til en personlig blog eller en ikke-kommerciel hjemmeside kan du få et ubegrænset gratis sprog.','Email address: '=>'E-mail-adresse: ','The email address is detected and pre-filled. This is the administrative email address entered in the Settings ➔ General tab. You can use another email address used to receive your API key.'=>'E-mailadressen registreres og udfyldes på forhånd. Det er den administrative e-mailadresse, der er indtastet i fanen Indstillinger ➔ Generelt. Du kan bruge en anden e-mailadresse, der bruges til at modtage din API-nøgle.','Website URL: '=>'Hjemmeside-URL: ','This is the URL of your website, it is detected and pre-filled automatically. Please check it and only enter the address of your production website (no test website or development environment).'=>'Dette er URL\'en til din hjemmeside, den registreres og udfyldes automatisk. Tjek det, og indtast kun adressen på din produktionshjemmeside (ingen testhjemmeside eller udviklingsmiljø).','Website language: '=>'Hjemmesidens sprog: ','This is the language of your website, defined by the associated API key. Make sure your website language is also correctly set in WordPress options (Settings ➔ General ➔ Website Language).'=>'Dette er sproget på din hjemmeside, som er defineret af den tilknyttede API-nøgle. Sørg for, at dit hjemmesidesprog også er indstillet korrekt i WordPress-indstillingerne (Indstillinger ➔ Generelt ➔ Hjemmesidesprog).','Language to add: '=>'Sprog, der skal tilføjes: ','This is the language you want to translate your website into. Be careful not to make a mistake because you will not be able to change the language afterwards.'=>'Det er det sprog, du vil oversætte din hjemmeside til. Pas på, at du ikke laver en fejl, for du kan ikke ændre sproget bagefter.','I have read and accept the'=>'Jeg har læst og accepterer','API terms of use'=>'Vilkår for brug af API','Website Locale: '=>'Webstedets beliggenhed: ','Get more target languages and advanced features: '=>'Få flere målsprog og avancerede funktioner: ','To translate your website into more languages and access advanced features, visit wpLingua website.'=>'Hvis du vil oversætte din hjemmeside til flere sprog og have adgang til avancerede funktioner, kan du besøge wpLinguas hjemmeside.','Use wpLingua on commercial website'=>'Brug wpLingua på en kommerciel hjemmeside','Allow search from all languages'=>'Tillad søgning fra alle sprog','Get more target languages'=>'Få flere målsprog','Visit wpLingua website'=>'Besøg wpLinguas hjemmeside','wpLingua - General settings'=>'wpLingua - Generelle indstillinger','Website language'=>'Sprog på hjemmesiden','Translated languages'=>'Oversatte sprog','Features'=>'Funktioner','API Key'=>'API-nøgle','Your website is being translated and will be ready soon.'=>'Din hjemmeside er ved at blive oversat og vil snart være klar.','In just a few seconds, your website will be multilingual, and search engines will be able to index these new pages. wpLingua detects all the texts on your pages and offers you a first automatically generated translation. All translations are editable: open the visual editor from the administration bar and edit them simply by clicking on the texts on your website.'=>'På få sekunder bliver din hjemmeside flersproget, og søgemaskinerne kan indeksere de nye sider. wpLingua registrerer alle tekster på dine sider og tilbyder dig en første automatisk genereret oversættelse. Alle oversættelser kan redigeres: Åbn den visuelle editor fra administrationslinjen, og rediger dem ved blot at klikke på teksterne på din hjemmeside.','Translation progress: '=>'Status for oversættelsen: ','Your website is now multilingual!'=>'Din hjemmeside er nu flersproget!','You can start visiting the translated version.'=>'Du kan nu gå ind på den oversatte version.','The first time a translated page is loaded, the translations are automatically generated and saved in the database. This may take some time (on first generation only) depending on the size of your content. This is why we advise you to browse your entire website for the first time in order to generate all the multilingual versions.'=>'Første gang en oversat side indlæses, genereres oversættelserne automatisk og gemmes i databasen. Det kan tage lidt tid (kun ved første generering) afhængigt af størrelsen på dit indhold. Derfor råder vi dig til at gennemse hele din hjemmeside første gang for at generere alle de flersprogede versioner.','All translations are editable: open the visual editor from the administration bar and edit them simply by clicking on the texts on your website.'=>'Alle oversættelser kan redigeres: Åbn den visuelle editor fra administrationslinjen, og rediger dem ved blot at klikke på teksterne på dit website.','Visit your multilingual website'=>'Besøg din flersprogede hjemmeside','Original website language: '=>'Hjemmesidens oprindelige sprog: ','Please choose an option'=>'Vælg venligst en mulighed','Original website language, defined by API key: '=>'Hjemmesidens oprindelige sprog, defineret af API-nøglen: ','If you have mistakenly selected the wrong language, you can delete the API key in the site options below and request a new API key.'=>'Hvis du ved en fejl har valgt det forkerte sprog, kan du slette API-nøglen i webstedsindstillingerne nedenfor og anmode om en ny API-nøgle.','Custom'=>'Brugerdefineret','Flag to use for this language: '=>'Flag, der skal bruges til dette sprog: ','Custom flag URL for this language: '=>'Brugerdefineret flag-URL for dette sprog: ','Important: space out the addition of new languages ​​by at least ten days and browse your site for the first time in the added languages. This promotes better indexing by search engines, reduces the load on your server and minimizes the risk of slowdowns on your site.'=>'Vigtigt: Tilføj nye sprog med mindst ti dages mellemrum, og gennemse dit websted for første gang på de tilføjede sprog. Det giver søgemaskinerne en bedre indeksering, reducerer belastningen på din server og minimerer risikoen for, at dit site bliver langsommere.','Add new target Language: '=>'Tilføj nyt målsprog: ','Add language'=>'Tilføj sprog','(Private)'=>'(Privat)','Move up'=>'Flyt op','Move down'=>'Flyt ned','Make this language private'=>'Gør dette sprog privat','Private languages will only be visible to logged-in users with editing rights. This option allows administrators to pre-generate and correct translations before they are accessible to the public.'=>'Private sprog vil kun være synlige for indloggede brugere med redigeringsrettigheder. Denne mulighed giver administratorer mulighed for at forhåndsgenerere og korrigere oversættelser, før de er tilgængelige for offentligheden.','Target languages enabled: '=>'Målsprog aktiveret: ','Access more target languages by upgrading your API key.'=>'Få adgang til flere målsprog ved at opgradere din API-nøgle.','Available languages: '=>'Tilgængelige sprog: ','wplingua.com : Upgrade your API key'=>'wplingua.com : Opgrader din API-nøgle','API translation features: '=>'API-oversættelsesfunktioner: ','The options below require extended access to the wpLingua API to be functional on your website.'=>'Nedenstående muligheder kræver udvidet adgang til wpLingua API for at kunne fungere på din hjemmeside.','Use of the free wpLingua API keys is reserved for personal blogs and non-profit websites; paid subscriptions are available for companies and commercial websites.'=>'Brug af de gratis wpLingua API-nøgler er forbeholdt personlige blogs og non-profit websites; betalte abonnementer er tilgængelige for virksomheder og kommercielle websites.','Search from translated languages'=>'Søg fra oversatte sprog','Enable visitors to search on your website in their own language.'=>'Gør det muligt for besøgende at søge på dit website på deres eget sprog.','Example: if your website is translated from English to French and you have a post named "Hello". When a French visitor searches for the term "Bonjour" on the website, this feature will translate it on the fly to "Hello" before launching the search. This will allow WordPress to find the post named "Hello" when your visitor has searched for "Bonjour".'=>'Eksempel: Hvis din hjemmeside er oversat fra engelsk til fransk, og du har et indlæg med navnet "Hello". Når en fransk besøgende søger efter udtrykket "Bonjour" på hjemmesiden, vil denne funktion oversætte det til "Hello", før søgningen startes. På den måde kan WordPress finde indlægget med navnet "Hello", når din besøgende har søgt efter "Bonjour".','SEO features: '=>'SEO-funktioner: ','Add hreflang tags to translated pages'=>'Tilføj hreflang-tags til oversatte sider','This option automatically adds hreflang tags to your pages that are available in multiple languages.'=>'Denne mulighed tilføjer automatisk hreflang-tags til dine sider, der er tilgængelige på flere sprog.','Hreflang tags are HTML metadata used to indicate the URLs of each language version of a page. They are not visible to visitors, but they allow search engines (Google, Bing, etc.) to identify the multilingual structure of the site and display the correct version according to the user\'s language.'=>'Hreflang-tags er HTML-metadata, der bruges til at angive URL\'erne for hver sprogversion af en side. De er ikke synlige for besøgende, men de gør det muligt for søgemaskiner (Google, Bing osv.) at identificere den flersprogede struktur på webstedet og vise den korrekte version i henhold til brugerens sprog.','Enable multilingual XML Sitemap'=>'Aktivér flersproget XML-sitemap','This option automatically adds your wpLingua translated pages into your XML Sitemap files.'=>'Denne mulighed tilføjer automatisk dine wpLingua-oversatte sider til dine XML Sitemap-filer.','An XML Sitemap is used by search engines (Google, Bing, etc.) to better discover and index the pages of your website. By default, only the default language pages are included. With this option enabled, all translated versions of your content will also be listed.'=>'Et XML-sitemap bruges af søgemaskiner (Google, Bing osv.) til bedre at finde og indeksere siderne på dit website. Som standard er det kun siderne på standardsproget, der er inkluderet. Hvis denne mulighed er aktiveret, vil alle oversatte versioner af dit indhold også blive vist.','This greatly improves SEO visibility, ensuring that search engines can easily find and index your content in every language.'=>'Det forbedrer i høj grad SEO-synligheden og sikrer, at søgemaskinerne nemt kan finde og indeksere dit indhold på alle sprog.','wpLingua uses a universal method that intercepts and extends sitemap. It works with the native WordPress sitemap and with popular SEO plugins such as Yoast SEO, Rank Math, All in One SEO, SEOPress, etc.'=>'wpLingua bruger en universel metode, der opfanger og udvider sitemap. Det fungerer med det oprindelige WordPress-sitemap og med populære SEO-plugins som Yoast SEO, Rank Math, All in One SEO, SEOPress osv.','Use wpLingua display for XML Sitemap'=>'Brug wpLingua-visning til XML-sitemap','This option replaces the default XML Sitemap stylesheet with wpLingua\'s custom display.'=>'Denne indstilling erstatter standard-stylesheetet til XML-sitemap med wpLinguas tilpassede visning.','When enabled, the XML Sitemap will use a wpLingua-designed stylesheet that visually displays all translated URLs directly under each original URL. This makes it easy to verify that all language versions are correctly included in your sitemap.'=>'Når denne funktion er aktiveret, bruger XML-sitemapet et af wpLingua designet stylesheet, der viser alle oversatte URL-adresser direkte under den enkelte originale URL. Det gør det nemt at kontrollere, at alle sprogversioner er korrekt medtaget i dit sitemap.','Note: This only affects how the sitemap is displayed in your browser. The actual XML data sent to search engines remains unchanged and fully compatible with all SEO standards.'=>'Bemærk: Dette påvirker kun, hvordan sitemappen vises i din browser. De faktiske XML-data, der sendes til søgemaskinerne, forbliver uændrede og er fuldt ud kompatible med alle SEO-standarder.','This option has no effect when using All In One SEO, as this plugin handles the display of translated links itself.'=>'Denne indstilling har ingen virkning, når du bruger All In One SEO, da dette plugin selv styrer visningen af oversatte links.','More features: '=>'Flere funktioner: ','Translation progress bar for editors'=>'Statusbjælke for oversættelse til redaktører','Enable progress bar: Smooth translations loading for editors'=>'Aktivér statuslinje: Glat indlæsning af oversættelser for redaktører','Activate a progress bar when a page requires the generation of more than 10 new string translations. This feature only applies to connected editors.'=>'Vis en statusbjælke, når en side kræver generering af mere end 10 nye strengoversættelser. Denne funktion gælder kun for tilknyttede redaktører.','This option automatically redirects visitors to the translated version of your site that matches their browser language when they land on the main homepage. It can improve user experience by showing content in the right language immediately, but depending on your setup, it may introduce side effects.'=>'Denne mulighed omdirigerer automatisk besøgende til den oversatte version af dit websted, der matcher deres browsersprog, når de lander på hovedhjemmesiden. Det kan forbedre brugeroplevelsen ved at vise indhold på det rigtige sprog med det samme, men afhængigt af din opsætning kan det medføre bivirkninger.','Disabled (recommended):'=>'Deaktiveret (anbefales):','No redirection is applied. Every visitor always sees the default homepage, regardless of their browser language. This is the safest option and ensures maximum compatibility with caching systems, SEO, and shared links. Recommended if you are unsure which option to choose.'=>'Der anvendes ingen omdirigering. Alle besøgende ser altid standardhjemmesiden, uanset deres browsersprog. Dette er den sikreste løsning og sikrer maksimal kompatibilitet med caching-systemer, SEO og delte links. Anbefales, hvis du er usikker på, hvilken mulighed du skal vælge.','JS only:'=>'Kun JS:','The redirect is handled with JavaScript, after the default homepage has loaded. This method works in almost all cases and avoids issues with caching plugins. However, it may cause a short flicker effect: users will briefly see the default page before being redirected to the translated version.'=>'Omdirigeringen håndteres med JavaScript, efter at standardhjemmesiden er indlæst. Denne metode virker i næsten alle tilfælde og undgår problemer med caching-plugins. Den kan dog forårsage en kortvarig flimmereffekt: Brugerne vil kortvarigt se standardsiden, før de bliver omdirigeret til den oversatte version.','PHP and JS:'=>'PHP og JS:','The redirect is performed server-side with PHP, which makes it faster and more seamless for visitors. In addition, a cookie is set via JavaScript to remember the user’s preferred language for future visits. While this provides the smoothest experience, it can sometimes conflict with caching systems (static pages, CDN, aggressive cache settings) and may cause incorrect redirects in certain setups.'=>'Omdirigeringen udføres på serversiden med PHP, hvilket gør det hurtigere og mere problemfrit for de besøgende. Desuden sættes en cookie via JavaScript for at huske brugerens foretrukne sprog ved fremtidige besøg. Selv om dette giver den bedste oplevelse, kan det nogle gange komme i konflikt med cachesystemer (statiske sider, CDN, aggressive cache-indstillinger) og kan forårsage forkerte omdirigeringer i visse opsætninger.','Disable (recommended)'=>'Deaktiver (anbefales)','Enable with JS only'=>'Aktivér kun med JS','Enable with PHP and JS'=>'Aktiver med PHP og JS','Website API key: '=>'Hjemmesidens API-nøgle: ','The API key connects the website to wpLingua\'s online services and automatic translation generators.'=>'API-nøglen forbinder hjemmesiden med wpLinguas onlinetjenester og automatiske oversættelsesgeneratorer.','Show API key'=>'Vis API-nøgle','Hide API key'=>'Skjul API-nøgle','API key status: '=>'Status for API-nøgle: ','Premium expiration: '=>'Udløb af præmie: ','wpLingua - Switcher settings'=>'wpLingua - Indstillinger for switcher','No target language selected.'=>'Intet målsprog valgt.','Preview'=>'Forhåndsvisning','Design'=>'Design','Layout: '=>'Layout: ','This option allow you to define the layout of the languages ​​in the switcher.'=>'Med denne indstilling kan du definere layoutet for sprogene i omskifteren.','Inline list: '=>'Inline-liste: ','the languages ​​are lined up next to each other.'=>'sprogene er stillet op ved siden af hinanden.','Block: '=>'Blok: ','the languages ​​are placed in columns, one under the other.'=>'sprogene er placeret i kolonner, det ene under det andet.','Dropdown: '=>'Dropdown: ','the languages ​​appear in a drop-down menu; this is recommended when your website offers several languages.'=>'sprogene vises i en rullemenu; dette anbefales, når din hjemmeside tilbyder flere sprog.','Displayed names: '=>'Visning af navne: ','This option allow you to choose how the languages names should be written in the switcher.'=>'Med denne indstilling kan du vælge, hvordan sprognavnene skal skrives i omskifteren.','Translated names: '=>'Oversatte navne: ','the name of the languages ​​is translated into the current language displayed.'=>'navnet på sprogene oversættes til det aktuelle sprog, der vises.','Original name: '=>'Oprindeligt navn: ','each language retains its name in its own language (English, Français, 日本語, Português, Español, etc.).'=>'hvert sprog beholder sit navn på sit eget sprog (English, Français, 日本語, Português, Español osv.).','Language ID: '=>'Sprog-ID: ','language names use language ID (FR, EN, DE, RU, etc.).'=>'sprognavne bruger sprog-ID (FR, EN, DE, RU osv.).','No display: '=>'Intet display: ','no text, only flags are displayed.'=>'ingen tekst, kun flag vises.','Flags style: '=>'Flags stil: ','This option allow you to choose the appearance of the flags in the switcher. '=>'Med denne indstilling kan du vælge, hvordan flagene skal se ud i omskifteren. ','Circle: '=>'Cirkel: ','display round flags.'=>'vise runde flag.','Rectangular: '=>'Rektangulær: ','display rectangular flags.'=>'viser rektangulære flag.','Wave: '=>'Bølge: ','display wavy flags.'=>'vise bølgede flag.','no display any flags, only the language name will be displayed.'=>'ikke viser nogen flag, vises kun sprognavnet.','You can also change the country flag or set a custom flag from wpLingua ➔ General settings. For example, you can set the flag of Mexico for Spanish instead of the flag of Spain.'=>'Du kan også ændre landets flag eller indstille et brugerdefineret flag fra wpLingua ➔ Generelle indstillinger. Du kan f.eks. indstille Mexicos flag til spansk i stedet for Spaniens flag.','Color theme: '=>'Farvetema: ','This option allows you to choose the color and border styles of the languages switcher.'=>'Denne mulighed giver dig mulighed for at vælge farve og kantstil for sprogomskifteren.','The color options offer 5 themes: '=>'Farveindstillingerne tilbyder 5 temaer: ','Light: '=>'Lys: ','white color in the background of the switcher.'=>'hvid farve i baggrunden af omskifteren.','Grey: '=>'Grå: ','grey background color.'=>'grå baggrundsfarve.','Dark: '=>'Mørk: ','black background color.'=>'sort baggrundsfarve.','Blur Black: '=>'Blur Black: ','transparent and blurred background color with black text and borders.'=>'gennemsigtig og sløret baggrundsfarve med sort tekst og kanter.','Blur White: '=>'Blur White: ','transparent and blurred background color with white text and borders.'=>'gennemsigtig og sløret baggrundsfarve med hvid tekst og kanter.','Each theme is then broken down by shape and border style:'=>'Hvert tema er derefter opdelt efter form og kantstil:','Double – Smooth: '=>'Dobbelt - Glat: ','the switcher will be framed by a double border with rounded corners.'=>'omskifteren bliver indrammet af en dobbelt kant med afrundede hjørner.','Double – Square: '=>'Dobbelt - Firkantet: ','double border with square corners.'=>'dobbelt kant med firkantede hjørner.','Simple – Smooth: '=>'Enkel - glat: ','single border with rounded corners.'=>'enkelt kant med afrundede hjørner.','Simple – Square: '=>'Enkel - firkantet: ','single border with square corners.'=>'enkelt kant med firkantede hjørner.','Custom CSS'=>'Brugerdefineret CSS','Set custom CSS: '=>'Indstil brugerdefineret CSS: ','The field below allows you to add custom CSS code that will run on all pages.'=>'I feltet nedenfor kan du tilføje brugerdefineret CSS-kode, som vil køre på alle sider.','First of all, note that the CSS class <code>.switcher-content</code> allows you to act on the entire block of the language switcher while the class <code>.wplng-langague</code> allows you to act on the languages ​​themselves.'=>'Først og fremmest skal du bemærke, at CSS-klassen <code>.switcher-content</code> giver dig mulighed for at handle på hele blokken med sprogomskifteren, mens klassen <code>.wplng-langague</code> giver dig mulighed for at handle på selve sprogene.','To change the background and border colors of languages, here is the CSS:'=>'Her er CSS\'en til at ændre baggrunds- og kantfarver på sprog:','More example on wplingua.com'=>'Flere eksempler på wplingua.com','Insertion'=>'Indsættelse','Automatic insert: '=>'Automatisk indsats: ','Choose a predefined location: '=>'Vælg en foruddefineret placering: ','Bottom right: '=>'Nederst til højre: ','the switcher is placed at the bottom right of the screen.'=>'omskifteren er placeret nederst til højre på skærmen.','Bottom Center: '=>'Nederst i midten: ','bottom center of the screen.'=>'nederst i midten af skærmen.','Bottom left: '=>'Nederst til venstre: ','bottom left of the screen.'=>'nederst til venstre på skærmen.','None: '=>'Ingen: ','the switcher is not inserted automatically.'=>'er omskifteren ikke indsat automatisk.','Shortcode switcher: '=>'Skift mellem kortkoder: ','If you want to insert the language switcher only in certain places on your website, you can use the shortcode provided for this purpose. Note that in this case, the previous option should be "None". This method is ideal for placing the switcher where you want it, whether you are using a Gutenberg block-based theme (FSE), a classic theme or even a page or theme builder like Divi, Elementor...'=>'Hvis du kun vil indsætte sprogomskifteren bestemte steder på din hjemmeside, kan du bruge den medfølgende kortkode til dette formål. Bemærk, at i dette tilfælde skal den forrige indstilling være "Ingen". Denne metode er ideel til at placere switchen, hvor du vil have den, uanset om du bruger et Gutenberg-blokbaseret tema (FSE), et klassisk tema eller endda en side- eller temabygger som Divi, Elementor ...','You can add parameters to the language selector shortcode, for example: '=>'Du kan tilføje parametre til kortkoden til sprogvælgeren, for eksempel: ','Here is a list of all available settings: '=>'Her er en liste over alle tilgængelige indstillinger: ','If a setting is not specified, the value entered on the language switcher options page will be used.'=>'Hvis der ikke er angivet en indstilling, anvendes den værdi, der er indtastet på siden med indstillinger for sprogskift.','Gutenberg & FSE: '=>'Gutenberg & FSE: ','Block wpLingua Switcher'=>'Bloker wpLingua Switcher','Block based themes, wpLingua offers a dedicated Gutenberg block. You can insert the switcher wherever you want, whether in the content or via the overall site editor.'=>'Blokbaserede temaer, wpLingua tilbyder en dedikeret Gutenberg-blok. Du kan indsætte omskifteren, hvor du vil, hvad enten det er i indholdet eller via den overordnede site-editor.','Switcher in menu: '=>'Switcher i menuen: ','Appearance ➔ Menus'=>'Udseende ➔ Menuer','If the active theme manages menus (classic theme), it is possible to add a language switcher. The design of these language switchers will be defined by the theme. Go to the Appearance ➔ Menu tab to add the wpLingua switcher as a menu item. It is also possible to add it as a sub-element.'=>'Hvis det aktive tema håndterer menuer (klassisk tema), er det muligt at tilføje en sprogomskifter. Designet af disse sprogomskiftere vil blive defineret af temaet. Gå til fanen Udseende ➔ Menu for at tilføje wpLingua-omskifteren som et menupunkt. Det er også muligt at tilføje den som et underelement.','wpLingua: Register'=>'wpLingua: Registrer dig','wpLingua: Settings'=>'wpLingua: Indstillinger','General settings'=>'Generelle indstillinger','wpLingua: Switcher'=>'wpLingua: Omskifter','Switcher'=>'Omskifter','wpLingua: Exclusion'=>'wpLingua: Udelukkelse','Exclusion'=>'Eksklusion','wpLingua: Dictionary'=>'wpLingua: Ordbog','Dictionary'=>'Ordbog','wplingua: Links & Medias'=>'wplingua: Links og medier','Links & Medias'=>'Links og medier','wpLingua: Website slugs'=>'wpLingua: Website-slug','Website slugs'=>'Website-slug','wpLingua: Translations'=>'wpLingua: Oversættelser','All translations'=>'Alle oversættelser','Thank you for choosing wpLingua!'=>'Tak, fordi du valgte wpLingua!','If you like wpLingua please leave us a %1$s rating. A huge thanks!'=>'Hvis du kan lide wpLingua, bedes du give os en %1$s-vurdering. En kæmpe tak!','five stars'=>'fem stjerner','Version'=>'Version','Settings'=>'Indstillinger','wpLingua - Translation solution for multilingual website'=>'wpLingua - Oversættelsesløsning til flersprogede hjemmesider','wpLingua is installed, but not yet configured. You are just a few clicks away from making your website multilingual!'=>'wpLingua er installeret, men endnu ikke konfigureret. Du er kun få klik fra at gøre din hjemmeside flersproget!','Go to the configuration page'=>'Gå til konfigurationssiden','wpLingua - Incompatible plugin detected'=>'wpLingua - Inkompatibelt plugin fundet','You have several translation plugins. This may result in unpredictable or incorrect behavior. For best results, use only one translation plugin at a time. These plugins can cause problems with wpLingua: '=>'Du har flere oversættelsesplugins. Det kan resultere i uforudsigelig eller ukorrekt adfærd. For at opnå de bedste resultater skal du kun bruge ét oversættelsesplugin ad gangen. Disse plugins kan forårsage problemer med wpLingua: ','Deactivate plugin: %1$s'=>'Deaktiver plugin: %1$s','Deactivate'=>'Deaktiver','Manage active plugins'=>'Administrer aktive plugins','wpLingua - Incompatible with multisite'=>'wpLingua - Inkompatibel med multisite','wpLingua is not compatible with multisite.'=>'wpLingua er ikke kompatibel med multisite.','wpLingua - Incompatible with WordPress installed in a subfolder'=>'wpLingua - Inkompatibel med WordPress installeret i en undermappe','wpLingua is not compatible with WordPress installed in a subfolder.'=>'wpLingua er ikke kompatibel med WordPress, der er installeret i en undermappe.','wpLingua - Incompatible PHP version'=>'wpLingua - Inkompatibel PHP-version','wpLingua is not compatible with your PHP version. wpLingua requires PHP 7.4 or higher.'=>'wpLingua er ikke kompatibel med din PHP-version. wpLingua kræver PHP 7.4 eller højere.','wpLingua - Incompatible HTACCESS file'=>'wpLingua - Inkompatibel HTACCESS-fil','It seems that a plugin was incorrectly deactivated and corrupted the site\'s HTACCESS file, preventing the correct redirection of translated pages. Please edit the ".htaccess" file located at the root of the site and delete the lines between :'=>'Det ser ud til, at et plugin blev deaktiveret forkert og ødelagde webstedets HTACCESS-fil, hvilket forhindrer korrekt omdirigering af oversatte sider. Rediger venligst filen ".htaccess", der ligger i roden af webstedet, og slet linjerne mellem :','wpLingua - Incompatible permalink structure'=>'wpLingua – Uforenelig permalink-struktur','wpLingua is not compatible with the "Plain" permalink structure. Please update your permalink settings to use "Post name" or "Custom Structure".'=>'wpLingua er ikke kompatibelt med permalink-strukturen »Plain«. Du bedes opdatere dine permalink-indstillinger, så du bruger »Indlægsnavn« eller »Brugerdefineret struktur«.','Manage permalink settings'=>'Administrer indstillinger for faste links','wpLingua - Website slugs'=>'wpLingua - Website-slugs','wpLingua - Website slug'=>'wpLingua - Website-slug','wpLingua - All slugs'=>'wpLingua - Alle slugs','wpLingua - Edit slug'=>'wpLingua - Rediger slug','Search slugs'=>'Søg slugs','All slug status'=>'Alle slug-statusser','Reviewed'=>'Anmeldt','Unreviewed'=>'Ikke anmeldt','Full reviewed'=>'Fuldt gennemgået','Partially reviewed'=>'Delvist gennemgået','Full unreviewed'=>'Fuldstændig uanmeldt','Slug status'=>'Slug-status','Slug status: '=>'Slug-status: ','Slug'=>'Slug','Flag for language: '=>'Flag for sprog: ',' - Original slug: '=>' - Oprindelig slug: ','Regenerate translation'=>'Regenereret oversættelse','Mark as review'=>'Marker som anmeldelse','Generate translation'=>'Generer oversættelse','Reviewed on '=>'Anmeldt den ',' - Slug translation: '=>' - Slug-oversættelse: ','Is reviewed'=>'Er gennemgået','Invalid parameters'=>'Ugyldig parameter','Invalid languages parameters'=>'Ugyldige sprogparametre','Invalid API response'=>'Ugyldigt API-svar','These options are used to add a language switcher in a menu. This language switcher automatically uses the menu design.'=>'Disse muligheder bruges til at tilføje en sprogomskifter i en menu. Denne sprogomskifter bruger automatisk menudesignet.','Displayed flag: '=>'Udstillet flag: ','Language switcher'=>'Sprogomskifter','Add to menu'=>'Tilføj til menu','wpLingua - Translations'=>'wpLingua - Oversættelser','wpLingua - Translation'=>'wpLingua - Oversættelse','wpLingua - All translations'=>'wpLingua - Alle oversættelser','wpLingua - Edit translation'=>'wpLingua - Rediger oversættelse','Search translations'=>'Søg i oversættelser','All translation status'=>'Alle oversættelsesstatusser','Translation status'=>'Oversættelsesstatus','Translation status: '=>'Oversættelsesstatus: ','All languages'=>'Alle sprog','Open edit page'=>'Åbn redigeringsside','Edit translation'=>'Rediger oversættelse','Invalid translation ID'=>'Ugyldigt oversættelses-ID','Invalid translation post'=>'Ugyldigt oversættelsesindlæg','Translation saving failed'=>'Gemning af oversættelse mislykkedes','Translation'=>'Oversættelse',' - Original text: '=>' - Original tekst: ',' - Translation: '=>' - Oversættelse: ','Discovery URL: '=>'URL til opdagelse: ','Error - Invalid data.'=>'Fejl - Ugyldige data.','Error - Invalid data (email address).'=>'Fejl - Ugyldige data (e-mailadresse).','Error - Invalid data (website URL).'=>'Fejl - Ugyldige data (websteds-URL).','Error - Invalid data (languages).'=>'Fejl - Ugyldige data (sprog).','Error - The API could not be called.'=>'Fejl - API\'en kunne ikke kaldes.','Error - API response not valid.'=>'Fejl - API-svaret er ikke gyldigt.','Code'=>'Kode','API returned an unexpected response.'=>'API returnerede et uventet svar.','You are about to exit without saving your changes. They will be lost if you continue. Would you like to leave anyway?'=>'Du er ved at afslutte uden at gemme dine ændringer. De vil gå tabt, hvis du fortsætter. Vil du gerne forlade stedet alligevel?','Save in progress...'=>'Gem i gang...','Translation API overloaded'=>'Oversættelses-API overbelastet','Translation API overloaded. Retry in a few minutes or '=>'Oversættelses-API overbelastet. Prøv igen om et par minutter eller ','upgrade your API key'=>'opgrader din API-nøgle',' to get priority API access.'=>' for at få prioriteret API-adgang.','Translation API overloaded. Please retry in a few minutes.'=>'Oversættelses-API overbelastet. Prøv igen om et par minutter.','Close'=>'Luk','Translation in progress'=>'Oversættelse i gang','In progress: Translation and saving of new texts'=>'I gang med at arbejde: Oversættelse og lagring af nye tekster','Error during translation.'=>'Der opstod en fejl under oversættelsen.','Error during translation. Check the browser console for more information.'=>'Der opstod en fejl under oversættelsen. Se browserens konsol for yderligere oplysninger.','Edit this translation'=>'Rediger denne oversættelse','Search'=>'Søg','Status'=>'Status','All'=>'Alle','Order'=>'Ordre','Occurrence order'=>'Rækkefølge for forekomst','Alphabetical - sources'=>'Alfabetisk - kilder','Alphabetical - translations'=>'Alfabetisk - oversættelser','SEO - Title:'=>'SEO – Titel:','SEO - Description:'=>'SEO – Beskrivelse:','Go to top'=>'Gå til toppen','...'=>'...','language'=>'sprog','switcher'=>'omskifter','multilanguage'=>'flersproget','multilingual'=>'flersproget','translate'=>'oversætte','translation'=>'oversættelse','flag'=>'flag','flags'=>'flag','wpLingua: languages switcher'=>'wpLingua: skift mellem sprog','Add a language switcher to your page.'=>'Tilføj en sprogomskifter til din side.','Languages switcher'=>'Skift mellem sprog','Display the wpLingua languages switcher.'=>'Vis wpLingua-sprogomskifteren.','Default'=>'Standard','https://wplingua.com/'=>'https://wplingua.com/','An all-in-one solution that makes your websites multilingual and translates them automatically, without word or page limits. The highlights: a free first language, an on-page visual editor for editing translations, a customizable language switcher, search engine optimization (SEO), self-hosted data and more!'=>'En alt-i-en-løsning, der gør dine hjemmesider flersprogede og oversætter dem automatisk uden ord- eller sidebegrænsninger. Højdepunkterne: et gratis førstesprog, en visuel editor på siden til redigering af oversættelser, en sprogomskifter, der kan tilpasses, søgemaskineoptimering (SEO), selvhostede data og meget mere!','wpLingua Translation Service'=>'wpLingua Oversættelsesservice']];
